var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"서쪽 침식쐐기 정리 끝!","JPN":"西の侵食楔、片付け完了！","ENG":"Corrupted Wedge in the west, cleared!","TWN":"西邊的侵蝕釘清除完畢！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아 아- 사부, 이제 잘 들리지?","JPN":"あ、あ。師匠、ばっちり聞こえるでしょ？","ENG":"Check, check. Master, you hear me now?","TWN":"喂喂，師父，聽得清楚嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"통신 문제는 해결됐군. 설치 작업을 시작해도 되겠어.","JPN":"通信の問題は解決したな。設置作業を始めてもよいだろう。","ENG":"Good, the comms issue is fixed. We can start the installation.","TWN":"通訊問題解決了，可以開始安裝了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"동쪽 현장 정리도 끝났다.","JPN":"東の現場も片付いた。","ENG":"East site's cleared too.","TWN":"東邊也清理完畢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대도 고생 많았네.","JPN":"そなたもご苦労だった。","ENG":"Good work.","TWN":"你也辛苦了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런데 걸어서 보고하러 온 건가? 앤디처럼 통신기를 써도 될 텐데 말이지.","JPN":"ところで、報告のためにわざわざ歩いて来たのか？　アンディーのように通信機でも構わんのだが。","ENG":"But you came all the way here to report? You could've just used a phone like Andy.","TWN":"不過你還特地走回來報告嗎？怎麼不像安狄一樣用手機回報就好？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"됐어. 전자기기는 내 손에 영 안 맞거든.","JPN":"いい。電子機器とは相性が悪いからな。","ENG":"Forget it. Gadgets and I don't get along.","TWN":"不，我跟電子產品不太合。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맞아, 사부. 지수 언니 같은 어르신한테 그런 건 무리라고.","JPN":"そうだよ。シノさんみたいなおばあさんには無理だよ。","ENG":"Exactly, Master. Expecting a granny like Jisoo to handle tech is pushing it.","TWN":"對啊，師父。像智秀姊那樣的阿姨不會用3Ｃ啦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"죽고 싶나, 꼬맹이?","JPN":"ガキ、死にたいのか？","ENG":"You want a piece of me, kid?","TWN":"想死嗎，小鬼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이제 그렇게 겁줘도 안 쫄아! 자기도 직원이면서 맨날 장비 조정 일은 떠넘기기만 하잖아!","JPN":"もう脅してもビビってやらないもんね！　自分だって社員のくせに、装備の調整とかいつも私に押しつけて！","ENG":"Hah! I'm not scared of you anymore! You're an employee too, but you always dump the gear work on us!","TWN":"我現在不怕你喔！你身為員工，卻總是把調整設備的工作推給我！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"연구소에서 반년 넘게 일한 사람이 폰도 못 만지는 기계치라니. 누가 믿겠어? 노력하는 시늉도 안 하잖아.","JPN":"研究所で半年以上働いてる人が携帯すら扱えない機械音痴ー？　そんなの信じるかっての。努力してる風でもないしさ。","ENG":"How does someone working here for six months still not know how to use a phone? You don't even pretend to try!","TWN":"在研究室工作半年多，說你是連手機都不會用3C白癡，誰會信？你連裝都不裝一下！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"정 원한다면 노력해주지.","JPN":"そんなに望むなら努力してやる。","ENG":"If you really want me to try, I'll do it.","TWN":"你想要的話，我是可以努力看看。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 너희의 비싼 장비를 쓸모없는 깡통으로 만들어버려도 감당할 수 있다면 말이야.","JPN":"私がお前たちの高い装備をスクラップにしてもいいならな。","ENG":"That is, if you can handle me turning all your fancy gear into junk.","TWN":"前提是你們能承受我把珍貴的設備變成廢鐵的話。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흥, 일하기 싫어서 일부러 고장내는 게 뻔하지. 누가 모를 줄 알고?","JPN":"ふん、働きたくなくてわざと壊すに決まってるよ。バレバレなんだから！","ENG":"Hmph! You'd just break it on purpose to get out of work. You think I don't know?","TWN":"哼，你只是不想工作故意弄壞而已。誰不知道？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"버튼 하나 누른 정도로 장비를 박살내는 인간이 세상에 실존할 리 없잖아!","JPN":"ボタン押しただけで装備を壊すような指なんて、実在するわけがない！","ENG":"No way someone's fingers can wreck a machine with one button press!","TWN":"世界上怎麼可能有人，只按一個按鈕就把設備弄壞！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"호오? 네 사부의 소중한 발명품이 내 손가락에 박살 나는 걸 다시 보고 싶단 뜻인가?","JPN":"ほお？　お前の師匠の大事な発明品が私の指でぶっ壊れるところをもう一度目にしたいとでも？","ENG":"Oh? Want to see your master's precious inventions crushed under my fingertips again?","TWN":"喔？你很想再看到你師父珍貴的發明在我手指下變成廢鐵嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어디 해보시지! 이번에야말로 무슨 속임수를 쓴 건지 간파해주겠어!","JPN":"やれるもんならやってみなよ！　今度こそ、どういうトリック使ってるのか見抜いてやる！","ENG":"Go ahead! This time I'll figure out your trick!","TWN":"來呀！這次我一定要看穿破你的手腳！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"크흠, 내 발명품으로 검증하는 건 그만 두지.","JPN":"ゴホン、某の発明品で検証するのはやめてくれぬか。","ENG":"Ahem. Enough testing my inventions for this.","TWN":"咳咳，還是別拿我的發明來做實驗吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지수 양은 지난 반년 간 충분히 노력했네. 너무 몰아붙이는 건 좋지 않아.","JPN":"シノ君はこの半年間、十分努力してくれた。あまり追いつめるのはよくない。","ENG":"Jisoo's done plenty these past six months. No need to push her.","TWN":"智秀這半年已經很努力了，別再逼她了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"너무해, 사부! 난 사부 편인데에-!","JPN":"ひどいよ、師匠！　私は師匠の味方なのに～！","ENG":"Come on, Master! I was on your side!","TWN":"師父，你怎麼這樣！我是在幫你欸！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"쯧.","JPN":"ちっ。","ENG":"Tsk.","TWN":"嘖。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러고 보니, 근래 제대로 쉬지도 못하고 일만 했군.","JPN":"そういえば、近頃は仕事詰めでまともな休暇も取れていなかったな。","ENG":"Come to think of it, we've all been working non-stop lately.","TWN":"這麼說來，最近我們都沒好好休息，一直在工作。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"장치 조율은 나 혼자로 충분하니, 두 사람은 간만에 도시로 쇼핑이나 다녀오는 게 어떻겠나?","JPN":"装備の調整は某一人で十分できる。2人は久々に都市で買い物でもして来たらどうだ？","ENG":"I can handle the adjustments alone. Why don't you two head into town for a shopping break?","TWN":"裝置的調整我來就好，你們兩個去城裡逛逛吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};